import{_ as n,C as l,o as s,c as o,E as a,w as i,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const f=JSON.parse('{"title":"Estonia Healthcare & HRT","description":"Transgender healthcare access in Estonia","frontmatter":{"layout":"doc","title":"Estonia Healthcare & HRT","description":"Transgender healthcare access in Estonia"},"headers":[],"relativePath":"europe/estonia/healthcare.md","filePath":"europe/estonia/healthcare.md","lastUpdated":null}'),c={name:"europe/estonia/healthcare.md"};function h(p,e,u,g,m,b){const t=l("Badge");return s(),o("div",null,[a(t,{variant:"yellow"},{default:i(()=>[...e[0]||(e[0]=[r("Gatekeeping Model",-1)])]),_:1}),a(t,{variant:"yellow"},{default:i(()=>[...e[1]||(e[1]=[r("Limited Clinics (Tallinn, Tartu)",-1)])]),_:1}),a(t,{variant:"green"},{default:i(()=>[...e[2]||(e[2]=[r("Prescription Portability (EU)",-1)])]),_:1}),e[3]||(e[3]=d('<h1 id="healthcare-hrt-in-estonia" tabindex="-1">Healthcare &amp; HRT in Estonia <a class="header-anchor" href="#healthcare-hrt-in-estonia" aria-label="Permalink to &quot;Healthcare &amp; HRT in Estonia&quot;">​</a></h1><h2 id="gatekeeping-model" tabindex="-1">Gatekeeping Model <a class="header-anchor" href="#gatekeeping-model" aria-label="Permalink to &quot;Gatekeeping Model&quot;">​</a></h2><p>Estonia operates a <strong>gatekeeping model</strong> for transgender healthcare:</p><ul><li><strong>Psychiatric diagnosis required</strong> to access HRT</li><li>Must be referred by a psychiatrist to an endocrinologist</li><li>Treatment decisions made by medical professionals, not solely by patient</li><li>Real-life experience period may be required before HRT</li></ul><h2 id="accessing-hrt" tabindex="-1">Accessing HRT <a class="header-anchor" href="#accessing-hrt" aria-label="Permalink to &quot;Accessing HRT&quot;">​</a></h2><h3 id="step-1-psychiatric-assessment" tabindex="-1">Step 1: Psychiatric Assessment <a class="header-anchor" href="#step-1-psychiatric-assessment" aria-label="Permalink to &quot;Step 1: Psychiatric Assessment&quot;">​</a></h3><ul><li>Contact a psychiatrist specializing in gender dysphoria</li><li>Available in Tallinn (North Estonia Medical Centre) and Tartu (Tartu University Hospital)</li><li>Waiting times: 2-6 months for initial appointment</li><li>Multiple sessions typically required for diagnosis</li></ul><h3 id="step-2-diagnosis" tabindex="-1">Step 2: Diagnosis <a class="header-anchor" href="#step-2-diagnosis" aria-label="Permalink to &quot;Step 2: Diagnosis&quot;">​</a></h3><ul><li>F64.0 (Transsexualism) or similar ICD diagnosis</li><li>Psychological evaluation and medical history review</li><li>Some clinics require 3-6 months of regular appointments</li></ul><h3 id="step-3-endocrinology-referral" tabindex="-1">Step 3: Endocrinology Referral <a class="header-anchor" href="#step-3-endocrinology-referral" aria-label="Permalink to &quot;Step 3: Endocrinology Referral&quot;">​</a></h3><ul><li>Referred to an endocrinologist for HRT</li><li>Blood tests for baseline hormone levels</li><li>Treatment plan developed by the medical team</li><li>Follow-up every 3-6 months initially</li></ul><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th></tr></thead><tbody><tr><td>North Estonia Medical Centre (PERH)</td><td>Tallinn</td><td>Psychiatric assessment, endocrinology</td></tr><tr><td>Tartu University Hospital</td><td>Tartu</td><td>Full gender clinic services</td></tr><tr><td>Private psychiatrists</td><td>Tallinn, Tartu</td><td>Assessment (shorter wait times)</td></tr><tr><td>Private endocrinologists</td><td>Tallinn</td><td>HRT prescription and monitoring</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><ul><li><strong>EU/EEA prescriptions</strong>: Valid in Estonia under EU mutual recognition</li><li><strong>Non-EU prescriptions</strong>: Must be verified by an Estonian doctor</li><li><strong>Importing medication</strong>: 3-month supply permitted with a doctor&#39;s letter</li><li><strong>Keep in original packaging</strong> with prescription labels</li><li><strong>Know generic names</strong> of your medications for local equivalents</li></ul><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><ul><li>Gender-affirming surgeries are <strong>not routinely available</strong> in Estonia</li><li>Some basic procedures (top surgery) available at Tallinn private clinics</li><li>Most Estonians travel abroad for surgeries (Thailand, Germany, Belgium)</li><li>Public funding for surgery abroad may be available in exceptional cases</li><li>Prior authorization from the Estonian Health Insurance Fund (Haigekassa) required</li></ul><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Estonian Resident</th><th>Non-Resident</th></tr></thead><tbody><tr><td>Public healthcare</td><td>Free (covered by health insurance)</td><td>Not available</td></tr><tr><td>Psychiatric assessment</td><td>Free (public)</td><td>€100-200</td></tr><tr><td>Endocrinology visit</td><td>Free (public)</td><td>€80-150</td></tr><tr><td>HRT (monthly)</td><td>€10-30</td><td>€30-60</td></tr><tr><td>Private psychiatrist</td><td>€60-100</td><td>€60-100</td></tr></tbody></table><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.perh.ee/" target="_blank" rel="noreferrer">North Estonia Medical Centre</a></li><li><a href="https://www.kliinikum.ee/" target="_blank" rel="noreferrer">Tartu University Hospital</a></li><li><a href="https://www.haigekassa.ee/" target="_blank" rel="noreferrer">Estonian Health Insurance Fund</a></li><li><a href="https://trans.ee/" target="_blank" rel="noreferrer">Trans in Estonia - Healthcare Guide</a></li></ul>',21))])}const T=n(c,[["render",h]]);export{f as __pageData,T as default};
